template <size_t NOut>
void legendre_map_dims(const npy_intp *dims, npy_intp *new_dims) {
    for (size_t i = 0; i < NOut; ++i) {
        new_dims[i] = dims[0];
    }
}

void new_legendre_map_dims(const npy_intp *dims, npy_intp *new_dims) { new_dims[0] = dims[0]; }

template <size_t NOut>
void assoc_legendre_map_dims(const npy_intp *dims, npy_intp *new_dims) {
    for (size_t i = 0; i < NOut; ++i) {
        new_dims[2 * i] = dims[0];
        new_dims[2 * i + 1] = dims[1];
    }
}

void sph_harm_map_dims(const npy_intp *dims, npy_intp *new_dims) {
    new_dims[0] = dims[0];
    new_dims[1] = dims[1];
}

void _poisson_binom_map_dims(const npy_intp *dims, npy_intp *new_dims) {
    new_dims[0] = dims[0];
}


// Helper to wrap a 1D std::vector in a contiguous mdspan
template <typename T>
auto _as_mdspan(std::vector<T>& vec) {
    return std::mdspan<T, std::dextents<ptrdiff_t, 1>>(vec.data(), vec.size());
}

template <typename T>
auto _as_mdspan(const std::vector<T>& vec) {
    return std::mdspan<const T, std::dextents<ptrdiff_t, 1>>(vec.data(), vec.size());
}

